import React, { useState, useEffect } from 'react';
import './App.css';
import './styles.css';
import Home from './pages/Home';
import Dashboard from './pages/Dashboard';
import Maintenance from './pages/Maintenance';
import Reports from './pages/Reports';
import About from './pages/About';

type PageType = 'home' | 'dashboard' | 'maintenance' | 'reports' | 'about';

function App() {
  const [currentPage, setCurrentPage] = useState<PageType>('home');

  useEffect(() => {
    // Handle hash-based routing
    const handleHashChange = () => {
      const hash = window.location.hash.slice(1).toLowerCase();
      if (hash && ['dashboard', 'maintenance', 'reports', 'about'].includes(hash)) {
        setCurrentPage(hash as PageType);
      } else {
        setCurrentPage('home');
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const handleNavClick = (page: PageType) => {
    if (page === 'home') {
      window.location.hash = '';
    } else {
      window.location.hash = `#${page}`;
    }
    setCurrentPage(page);
  };

  return (
    <div className="App">
      <header className="header">
        <h1>EV Smart Maintenance</h1>
      </header>
      <nav>
        <a href="#/" onClick={() => handleNavClick('home')} className={currentPage === 'home' ? 'active' : ''}>Home</a>
        <a href="#/dashboard" onClick={() => handleNavClick('dashboard')} className={currentPage === 'dashboard' ? 'active' : ''}>Dashboard</a>
        <a href="#/maintenance" onClick={() => handleNavClick('maintenance')} className={currentPage === 'maintenance' ? 'active' : ''}>Maintenance</a>
        <a href="#/reports" onClick={() => handleNavClick('reports')} className={currentPage === 'reports' ? 'active' : ''}>Reports</a>
        <a href="#/about" onClick={() => handleNavClick('about')} className={currentPage === 'about' ? 'active' : ''}>About</a>
      </nav>
      <main>
        {currentPage === 'home' && <Home />}
        {currentPage === 'dashboard' && <Dashboard />}
        {currentPage === 'maintenance' && <Maintenance />}
        {currentPage === 'reports' && <Reports />}
        {currentPage === 'about' && <About />}
      </main>
      <footer>
        <p>&copy; 2026 FutureNow Energy. All rights reserved.</p>
      </footer>
    </div>
  );
}

export default App;
